3:  
4:  interface User {
5:    id: string;
6:    email: string;
7:    userType: 'client' | 'provider';
8:    firstName: string;
9:    lastName: string;
10:   county: string;
11:   organizationName?: string;
12: }
13: 
14: interface Provider {
15:   id: string;
16:   providerCode: string;
17:   gender: string;
18:   phoneNumber: string;
19:   subscriptionStatus: string;
20:   photoUrl: string;
21: }
22: 
23: interface UserContextType {
24:   user: User | null;
25:   provider: Provider | null;
26:   setUser: (user: User | null) => void;
27:   setProvider: (provider: Provider | null) => void;
28:   logout: () => void;
29: }
30: 
31: const UserContext = createContext<UserContextType | undefined>(undefined);
32: 
33: export function UserProvider({ children }: { children: ReactNode }) {
34:   const [user, setUser] = useState<User | null>(null);
35:   const [provider, setProvider] = useState<Provider | null>(null);
36: 
37:   const logout = () => {
38:     console.log('User logged out');
39:     setUser(null);
40:     setProvider(null);
41:   };
42: 
43:   return (
44:     <UserContext.Provider value={{ user, provider, setUser, setProvider, logout }}>
45:       {children}
46:     </UserContext.Provider>
47:   );
48: }
49: 
50: export function useUser() {
51:   const context = useContext(UserContext);
52:   if (context === undefined) {
53:     throw new Error('useUser must be used within a UserProvider');
54:   }
55:   return context;
56: }
