9:  /**
10:  * Helper function to make API calls with proper error handling
11:  */
12: export async function apiCall<T = any>(
13:   endpoint: string,
14:   options?: RequestInit
15: ): Promise<T> {
16:   const url = `${BACKEND_URL}${endpoint}`;
17:   
18:   console.log(`API Call: ${options?.method || 'GET'} ${url}`);
19:   if (options?.body) {
20:     console.log('Request body:', options.body);
21:   }
22: 
23:   try {
24:     const response = await fetch(url, {
25:       ...options,
26:       headers: {
27:         'Content-Type': 'application/json',
28:         ...options?.headers,
29:       },
30:     });
31: 
32:     // Get the response text first to see what we're actually receiving
33:     const responseText = await response.text();
34:     console.log(`Raw response (${response.status}):`, responseText.substring(0, 200));
35: 
36:     // Try to parse as JSON
37:     let data;
38:     try {
39:       data = JSON.parse(responseText);
40:     } catch (parseError) {
41:       console.error('Failed to parse response as JSON:', parseError);
42:       console.error('Response was:', responseText.substring(0, 500));
43:       throw new Error(`Server returned invalid JSON. Response: ${responseText.substring(0, 100)}`);
44:     }
45:     
46:     console.log(`API Response (${response.status}):`, data);
47: 
48:     if (!response.ok) {
49:       throw new Error(data.error || `API request failed with status ${response.status}`);
50:     }
51: 
52:     return data;
53:   } catch (error) {
54:     console.error(`API Error for ${endpoint}:`, error);
55:     throw error;
56:   }
57: }
